class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right
def lca_in_binary_tree(root: TreeNode, p: int, q: int) -> int:
    ans = None
    def dfs(node):
        nonlocal ans
        if not node:
            return False
        left = dfs(node.left)
        right = dfs(node.right)
        mid = (node.val == p) or (node.val == q)
        if (mid and left) or (mid and right) or (left and right):
            ans = node
        return left or right or mid
    dfs(root)
    return ans.val if ans else None

